import sys
def input():
    return sys.stdin.readline().strip()


s = input()
n = len(s)

if s[0] != '[' or s[-1] != ']':
    print(-1)
    exit(0)

for i in range(1, n - 1):
    if s[i] == '|':
        break

for j in range(n - 2, i, -1):
    if s[j] == '|':
        break

if i >= j:
    print(-1)
else:
    print(j - i + 1)
